#!/usr/bin/env node
/**
 * DEPENDENCIES.md Validation Script
 *
 * Validates the structure and quality of DEPENDENCIES.md generated by ai1st-arch-legacy-analysis-lite.
 * Called by Claude hooks (PostToolUse) or manually for verification.
 *
 * Usage: node validate-dependencies-md.js [file-path]
 *        If no file-path provided, searches for DEPENDENCIES.md in current directory
 *
 * Exit codes:
 *   0 - Validation passed
 *   1 - Validation failed (missing sections, placeholders, or no code references)
 */

const fs = require('fs');
const path = require('path');

// Configuration
const REQUIRED_SECTIONS = [
  { name: 'API Endpoints section', pattern: /## \d+\. API Endpoints/i },
  { name: 'DTOs section', pattern: /## \d+\. DTOs/i },
  { name: 'Business Rules section', pattern: /## \d+\. Business Rules/i },
  { name: 'JSP Pages section', pattern: /## \d+\. JSP Pages/i }
];

const QUALITY_CHECKS = [
  {
    name: 'File:line references present',
    pattern: /\w+\.(java|cs|sql):\d+/g,
    minMatches: 3,
    invert: false
  },
  {
    name: 'No TBD placeholders',
    pattern: /\bTBD\b/gi,
    maxMatches: 0,
    invert: true
  },
  {
    name: 'No TODO placeholders',
    pattern: /\bTODO\b/gi,
    maxMatches: 0,
    invert: true
  },
  {
    name: 'No PLACEHOLDER markers',
    pattern: /\bPLACEHOLDER\b/gi,
    maxMatches: 0,
    invert: true
  },
  {
    name: 'Has ID references (INT-nnn, LBR-nnn, DTO-nnn)',
    pattern: /(INT|LBR|DTO)-\d{3}/g,
    minMatches: 1,
    invert: false
  }
];

function validateDependenciesMd(filePath) {
  console.log(`\n=== DEPENDENCIES.md Validation ===\n`);
  console.log(`File: ${filePath}\n`);

  // Check file exists
  if (!fs.existsSync(filePath)) {
    console.error(`ERROR: File not found: ${filePath}`);
    process.exit(1);
  }

  const content = fs.readFileSync(filePath, 'utf8');
  const lines = content.split('\n').length;
  console.log(`Lines: ${lines}\n`);

  let failures = [];
  let warnings = [];

  // Check required sections
  console.log('--- Required Sections ---');
  REQUIRED_SECTIONS.forEach(section => {
    const found = section.pattern.test(content);
    if (found) {
      console.log(`  [PASS] ${section.name}`);
    } else {
      console.log(`  [FAIL] ${section.name}`);
      failures.push(`Missing: ${section.name}`);
    }
  });

  // Check quality requirements
  console.log('\n--- Quality Checks ---');
  QUALITY_CHECKS.forEach(check => {
    const matches = content.match(check.pattern) || [];
    const matchCount = matches.length;

    if (check.invert) {
      // For "no placeholder" checks - fail if found
      if (matchCount > (check.maxMatches || 0)) {
        console.log(`  [FAIL] ${check.name} (found ${matchCount})`);
        failures.push(`${check.name}: found ${matchCount} occurrences`);
      } else {
        console.log(`  [PASS] ${check.name}`);
      }
    } else {
      // For "must have" checks - fail if not enough
      if (matchCount < (check.minMatches || 1)) {
        console.log(`  [FAIL] ${check.name} (found ${matchCount}, need ${check.minMatches})`);
        failures.push(`${check.name}: found ${matchCount}, need at least ${check.minMatches}`);
      } else {
        console.log(`  [PASS] ${check.name} (found ${matchCount})`);
      }
    }
  });

  // Check minimum line count
  console.log('\n--- Size Check ---');
  if (lines < 50) {
    console.log(`  [WARN] File seems too short (${lines} lines, expected 100+)`);
    warnings.push(`File may be incomplete: only ${lines} lines`);
  } else if (lines < 100) {
    console.log(`  [WARN] File shorter than expected (${lines} lines)`);
    warnings.push(`File shorter than expected: ${lines} lines`);
  } else {
    console.log(`  [PASS] File size adequate (${lines} lines)`);
  }

  // Summary
  console.log('\n=== Summary ===\n');

  if (failures.length > 0) {
    console.error(`VALIDATION FAILED (${failures.length} issues):\n`);
    failures.forEach(f => console.error(`  - ${f}`));
    process.exit(1);
  }

  if (warnings.length > 0) {
    console.log(`VALIDATION PASSED with ${warnings.length} warning(s):\n`);
    warnings.forEach(w => console.log(`  - ${w}`));
  } else {
    console.log('VALIDATION PASSED - All checks passed.\n');
  }

  process.exit(0);
}

// Main execution
function main() {
  let filePath = process.argv[2];

  if (!filePath) {
    // Search for DEPENDENCIES.md in current directory and subdirectories
    const searchPaths = [
      'DEPENDENCIES.md',
      'lite-analysis/DEPENDENCIES.md',
      'work/DEPENDENCIES.md'
    ];

    for (const searchPath of searchPaths) {
      if (fs.existsSync(searchPath)) {
        filePath = searchPath;
        break;
      }
    }

    if (!filePath) {
      console.error('ERROR: No file path provided and DEPENDENCIES.md not found in common locations.');
      console.error('Usage: node validate-dependencies-md.js <path-to-DEPENDENCIES.md>');
      process.exit(1);
    }
  }

  validateDependenciesMd(filePath);
}

main();
